{
  "summary": "This paper proposes Contrastive Novelty Learning (CNL), a method for open-set selective classification in text that leverages large language models to generate novel out-of-distribution examples and trains classifiers with a contrastive confidence loss to reduce overconfidence on OOD inputs. Extensive experiments on multiple NLP datasets demonstrate improved OOD detection and selective classification performance without sacrificing in-distribution accuracy.",
  "strengths": [
    {
      "point": "Novel approach to generating OOD examples for text classification using large language models",
      "evidence": "The paper introduces Novelty Prompting, a two-stage LLM-based method to generate novel class labels and corresponding examples that simulate realistic open-set shifts."
    },
    {
      "point": "Contrastive Confidence Loss (CCL) effectively reduces confidence on OOD examples without harming ID accuracy",
      "evidence": "CCL penalizes only when OOD confidence exceeds ID confidence, allowing flexible treatment of noisy generated examples and maintaining or improving ID accuracy compared to Outlier Exposure."
    },
    {
      "point": "Comprehensive empirical evaluation across multiple datasets and classifiers",
      "evidence": "Experiments on 14 splits across 4 NLP datasets show consistent improvements in AUAC and AUROC over strong baselines including ensembles, contrastive training, and OE."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent NLP-specific synthetic OOD generation methods and selective classification baselines",
      "evidence": "The paper does not compare against adversarial perturbations, back-translation, controlled text generation methods, or uncertainty calibration techniques like deep ensembles and MC dropout."
    },
    {
      "point": "Insufficient methodological details and reproducibility information",
      "evidence": "Exact prompt templates, synonym filtering criteria, training hyperparameters, and data splits are not fully specified, hindering replication."
    },
    {
      "point": "Limited evaluation metrics and missing statistical significance testing",
      "evidence": "Only AUAC and AUROC are reported without calibration metrics, precision/recall, or confidence intervals to assess robustness of improvements."
    },
    {
      "point": "No analysis of computational cost, overfitting risks, or failure modes",
      "evidence": "The paper does not discuss resource requirements for LLM generation, potential overfitting to synthetic OOD data, or provide qualitative error analysis."
    },
    {
      "point": "Experiments limited to English and small datasets with few classes",
      "evidence": "Datasets have small class counts and no evaluation on larger, multilingual, or more complex classification tasks."
    }
  ],
  "questions": [
    {
      "question": "How does CNL perform compared to recent NLP-specific OOD generation and selective classification methods?",
      "motivation": "Understanding relative gains over state-of-the-art NLP baselines is critical to assess the novelty and practical impact."
    },
    {
      "question": "What are the computational costs and scalability implications of using large LLMs for novelty prompting?",
      "motivation": "Resource requirements affect feasibility and adoption in real-world applications."
    },
    {
      "question": "How robust is CNL to noisy or imperfect generated OOD examples, and does it generalize beyond synthetic distributions?",
      "motivation": "Ensuring generalization to real-world novel classes is essential for practical selective classification."
    },
    {
      "question": "Can the method be extended or adapted to larger-scale, multilingual, or hierarchical classification tasks?",
      "motivation": "Demonstrating generalizability would broaden applicability and impact."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
